def is_number(s: str) -> bool:
    if not s:
        return False

    i = 0
    n = len(s)

    # Optional leading sign
    if s[i] in "+-":
        i += 1
        if i == n:
            return False

    digits_before = 0
    while i < n and s[i].isdigit():
        i += 1
        digits_before += 1

    digits_after = 0
    if i < n and s[i] == ".":
        i += 1
        while i < n and s[i].isdigit():
            i += 1
            digits_after += 1

    # Must have digits on at least one side of decimal point
    if digits_before == 0 and digits_after == 0:
        return False

    # Optional exponent
    if i < n and s[i] in "eE":
        i += 1
        if i == n:
            return False

        if s[i] in "+-":
            i += 1
            if i == n:
                return False

        exp_digits = 0
        while i < n and s[i].isdigit():
            i += 1
            exp_digits += 1

        if exp_digits == 0:
            return False

    return i == n
```

