def edit_distance(a: str, b: str) -> int:
    if len(a) < len(b):
        a, b = b, a

    prev = list(range(len(b) + 1))

    for i, ca in enumerate(a, 1):
        curr = [i]
        for j, cb in enumerate(b, 1):
            curr.append(
                min(
                    prev[j] + 1,                 # delete
                    curr[j - 1] + 1,             # insert
                    prev[j - 1] + (ca != cb),    # replace
                )
            )
        prev = curr

    return prev[-1]
