def decode_ways(s: str) -> int:
    if not s:
        return 0

    prev2, prev1 = 1, 0 if s[0] == "0" else 1

    for i in range(1, len(s)):
        curr = 0

        if s[i] != "0":
            curr += prev1

        two_digit = int(s[i - 1:i + 1])
        if 10 <= two_digit <= 26:
            curr += prev2

        prev2, prev1 = prev1, curr

    return prev1
```
